    if not s or not isinstance(s, str):
        return []
    try:
        arr = json.loads(s)
        codes = []
        for it in arr:
            if isinstance(it, dict):
                code = it.get('code')
                if code:
                    codes.append(code)
            elif isinstance(it, str):
                codes.extend(re.findall(r'[A-Z]\d{2}[A-Z0-9]*/?\d*', it))
