    except Exception:
        # fallback regex
        return re.findall(r'[A-Z]\d{2}[A-Z0-9]*/?\d*', s)

# aggregate counts per level4 CPC group by filing year
counts = defaultdict(lambda: defaultdict(int))

for rec in records:
